import React, { useState, useEffect } from 'react';
import {
  HardDrive,
  RefreshCw,
  Play,
  Download,
  Trash2,
  Calendar,
  Clock,
  CheckCircle,
  XCircle,
  Loader2
} from 'lucide-react';

function Backups({ devices, loading, onRefresh, onRunBackup }) {
  const [backups, setBackups] = useState([]);
  const [loadingBackups, setLoadingBackups] = useState(true);

  useEffect(() => {
    // Simular carregamento de backups
    setTimeout(() => {
      setBackups([
        { id: '1', device_id: 1, device_name: 'BRAS_NE8000', filename: 'backup_2026-02-14_01-00.cfg', created_at: '2026-02-14 01:00', size: '245 KB', status: 'success' },
        { id: '2', device_id: 2, device_name: 'PPPoE_CARDOSO_MOREIRA', filename: 'backup_2026-02-14_03-00.cfg', created_at: '2026-02-14 03:00', size: '128 KB', status: 'success' },
        { id: '3', device_id: 1, device_name: 'BRAS_NE8000', filename: 'backup_2026-02-13_01-00.cfg', created_at: '2026-02-13 01:00', size: '243 KB', status: 'success' },
      ]);
      setLoadingBackups(false);
    }, 500);
  }, []);

  const handleRunBackup = async (deviceId) => {
    setBackups(prev => [...prev, {
      id: Date.now().toString(),
      device_id: deviceId,
      device_name: devices.find(d => d.id === deviceId)?.name || 'Unknown',
      filename: 'backup_running...',
      created_at: new Date().toLocaleString('pt-BR'),
      size: '-',
      status: 'running',
    }]);
    await onRunBackup(deviceId);
  };

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex flex-col sm:flex-row gap-4 justify-between">
        <div>
          <h1 className="text-3xl font-bold tracking-tight">Backups</h1>
          <p className="text-muted-foreground">Gerenciamento de backups de configuração</p>
        </div>
        <button onClick={onRefresh} disabled={loading} className="px-4 py-2 border border-border rounded-lg hover:bg-secondary flex items-center gap-2 disabled:opacity-50">
          <RefreshCw className={'h-4 w-4 ' + (loading ? 'animate-spin' : '')} /> Atualizar
        </button>
      </div>

      {/* Quick Backup */}
      <div className="bg-card rounded-lg border border-border p-6">
        <h2 className="text-lg font-semibold mb-4">Backup Rápido</h2>
        <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
          {devices.filter(d => d.backup_enabled).map((device) => (
            <div key={device.id} className="flex items-center justify-between p-4 bg-secondary/50 rounded-lg">
              <div>
                <div className="font-medium">{device.name}</div>
                <div className="text-sm text-muted-foreground">{device.backup_frequency} às {device.backup_time}</div>
              </div>
              <button
                onClick={() => handleRunBackup(device.id)}
                className="p-2 bg-primary text-white rounded-lg hover:bg-primary/90"
              >
                <Play className="h-4 w-4" />
              </button>
            </div>
          ))}
        </div>
      </div>

      {/* Backup List */}
      <div className="bg-card rounded-lg border border-border overflow-hidden">
        <div className="p-4 border-b border-border">
          <h2 className="text-lg font-semibold">Histórico de Backups</h2>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full">
            <thead className="bg-secondary/30">
              <tr>
                <th className="text-left p-4 text-sm font-medium text-muted-foreground">Dispositivo</th>
                <th className="text-left p-4 text-sm font-medium text-muted-foreground">Arquivo</th>
                <th className="text-left p-4 text-sm font-medium text-muted-foreground">Data/Hora</th>
                <th className="text-left p-4 text-sm font-medium text-muted-foreground">Tamanho</th>
                <th className="text-left p-4 text-sm font-medium text-muted-foreground">Status</th>
                <th className="text-right p-4 text-sm font-medium text-muted-foreground">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-border">
              {backups.map((backup) => (
                <tr key={backup.id} className="hover:bg-secondary/30">
                  <td className="p-4 font-medium">{backup.device_name}</td>
                  <td className="p-4 text-sm font-mono">{backup.filename}</td>
                  <td className="p-4 text-sm text-muted-foreground">{backup.created_at}</td>
                  <td className="p-4 text-sm">{backup.size}</td>
                  <td className="p-4">
                    {backup.status === 'success' && <span className="flex items-center gap-1 text-green-500"><CheckCircle className="h-4 w-4" /> Sucesso</span>}
                    {backup.status === 'failed' && <span className="flex items-center gap-1 text-red-500"><XCircle className="h-4 w-4" /> Falhou</span>}
                    {backup.status === 'running' && <span className="flex items-center gap-1 text-yellow-500"><Loader2 className="h-4 w-4 animate-spin" /> Executando</span>}
                  </td>
                  <td className="p-4 text-right">
                    <div className="flex items-center justify-end gap-2">
                      <button className="p-2 hover:bg-secondary rounded" title="Download">
                        <Download className="h-4 w-4" />
                      </button>
                      <button className="p-2 hover:bg-secondary text-red-500 rounded" title="Excluir">
                        <Trash2 className="h-4 w-4" />
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
          {loadingBackups && (
            <div className="p-8 text-center text-muted-foreground">
              <Loader2 className="h-8 w-8 mx-auto animate-spin mb-2" />
              Carregando backups...
            </div>
          )}
          {!loadingBackups && backups.length === 0 && (
            <div className="p-8 text-center text-muted-foreground">Nenhum backup encontrado</div>
          )}
        </div>
      </div>
    </div>
  );
}

export default Backups;
